import{_ as i,o as a,c as s,ak as l}from"./chunks/framework.Dpc0wyhY.js";const g=JSON.parse('{"title":"Public CDN files","description":"","frontmatter":{},"headers":[],"relativePath":"grindr-api/media/public-cdn-files.md","filePath":"grindr-api/media/public-cdn-files.md"}'),o={name:"grindr-api/media/public-cdn-files.md"};function d(t,e,c,r,n,h){return a(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="public-cdn-files" tabindex="-1">Public CDN files <a class="header-anchor" href="#public-cdn-files" aria-label="Permalink to “Public CDN files”">​</a></h1><p>CDN files that are public are accessible directly using their hash, e.g. <a href="#profile-images">profile images</a></p><p>Base URL:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://cdns.grindr.com</span></span></code></pre></div><h2 id="profile-images" tabindex="-1">Profile images <a class="header-anchor" href="#profile-images" aria-label="Permalink to “Profile images”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/images/profile/{size}/{mediaHash}</span></span></code></pre></div><p>One side will always be the requested size and another will be less or equal to the requested size.</p><p>Available sizes for <code>{size}</code> parameter:</p><ul><li><code>2048x2048</code> (might be unavailable)</li><li><code>1024x1024</code></li><li><code>480x480</code></li><li><code>320x320</code></li></ul><h2 id="thumbnails-images" tabindex="-1">Thumbnails images <a class="header-anchor" href="#thumbnails-images" aria-label="Permalink to “Thumbnails images”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/images/thumb/{size}/{mediaHash}</span></span></code></pre></div><p>Image will be cropped at center and both sides will be exactly the requested size.</p><p>Available sizes for <code>{size}</code> parameter:</p><ul><li><code>480x480</code> (might be unavailable)</li><li><code>320x320</code></li><li><code>75x75</code></li></ul><h2 id="grindr-gaymoji" tabindex="-1">Grindr Gaymoji <a class="header-anchor" href="#grindr-gaymoji" aria-label="Permalink to “Grindr Gaymoji”">​</a></h2><p>List gaymojis:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>GET /grindr/chat/gaymoji</span></span></code></pre></div><p>Response:</p><p>Formatted JSON object:</p><ul><li><code>lastUpdateTime</code> — unix timestamp in milliseconds</li><li><code>gaymoji</code> — array of objects <ul><li><code>name</code> — unique identificator consisting of alphanumeric characters, hyphens and underscores</li><li><code>id</code> — same as <code>name</code> + <code>.png</code></li><li><code>category</code> — <a href="#gaymojicategory">GaymojiCategory</a></li></ul></li><li><code>category</code> — array of objects <ul><li><code>name</code> — <a href="#gaymojicategory">GaymojiCategory</a></li><li><code>expiredTime</code> — unix timestamp in milliseconds, may be <code>0</code></li></ul></li></ul><p>The image file assosiated with the Gaymoji is hosted at:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/grindr/chat/gaymoji/{id}</span></span></code></pre></div><p>ID must include file extension.</p><h2 id="gaymojicategory" tabindex="-1">GaymojiCategory <a class="header-anchor" href="#gaymojicategory" aria-label="Permalink to “GaymojiCategory”">​</a></h2><p>One of the following values:</p><ul><li><code>body</code></li><li><code>dating+sex</code></li><li><code>featured</code></li><li><code>holiday</code></li><li><code>mood</code></li><li><code>objects</code></li><li><code>profile</code></li><li><code>wen_ching_taiwan_stickers</code></li></ul>',26)])])}const m=i(o,[["render",d]]);export{g as __pageData,m as default};
